// ---------------------------------------------------------------------------
// Data layer — loads REAL Urban Rivals card data (generated by
// tools/fetch-cards.js into data/cards-data.json, scraped from iClintz).
//
// Nothing here is hard-coded: clans, names, art, stats, abilities & bonuses all
// come from the fetched JSON. We build CLANS / CARDS / CARD_BY_ID + level helpers
// and expose a promise `window.URBC_DATA_READY` the app awaits before rendering.
// ---------------------------------------------------------------------------
(function (root) {
  // Thematic colours per clan (for frames / chips). Falls back to a hashed hue.
  const COLORS = {
    allstars:"#f59e0b", bangers:"#16a34a", berzerk:"#f97316", cosmohnuts:"#a855f7",
    dominion:"#eab308", fangpiclang:"#dc2626", freaks:"#fb923c", frozn:"#38bdf8",
    gheist:"#b91c1c", ghostown:"#a16207", hive:"#ca8a04", huracan:"#e11d48",
    jungo:"#22c55e", junkz:"#ec4899", komboka:"#14b8a6", lajunta:"#4d7c0f",
    leader:"#eab308", montana:"#991b1b", nightmare:"#7c3aed", oblivion:"#6d28d9",
    oculus:"#06b6d4", paradox:"#d946ef", piranas:"#0d9488", pussycats:"#db2777",
    raptors:"#ea580c", rescue:"#ef4444", riots:"#f59e0b", roots:"#65a30d",
    sakrohm:"#10b981", sentinel:"#3b82f6", skeelz:"#8b5cf6", tolvack:"#0ea5e9",
    uluwatu:"#0ea5e9", uppers:"#facc15", vortex:"#22d3ee", zenith:"#64748b",
  };
  function hashHue(s) { let h = 0; for (let i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) | 0; return `hsl(${Math.abs(h) % 360} 60% 55%)`; }
  const colorFor = (k) => COLORS[k] || hashHue(k);

  let CLANS = {}, CLAN_ORDER = [], CARDS = [], CARD_BY_ID = {};

  function minLevel(card) { return card.stars >= 5 ? 3 : card.stars >= 4 ? 2 : 1; }
  function xpForLevel(card, level) { return 20 + (level - 1) * 12 + (card.stars - 2) * 6; }
  function xpToMax(card) { let t = 0; for (let l = minLevel(card); l < card.stars; l++) t += xpForLevel(card, l); return t; }

  function cardStatsAtLevel(card, level) {
    const lvl = Math.max(minLevel(card), Math.min(card.stars, (level | 0) || minLevel(card)));
    const damage = Math.max(1, card.damage - (card.stars - lvl));
    return {
      id: card.id, clan: card.clan, name: card.name, rarity: card.rarity, art: card.art,
      stars: card.stars, level: lvl, maxLevel: card.stars, minLevel: minLevel(card),
      power: card.power, damage,
      ability: card.ability, abilityText: card.abilityText, abilityLevel: card.abilityLevel,
      abilityActive: !!card.ability && lvl >= card.abilityLevel,
    };
  }

  function build(data) {
    const parse = root.parseEffect || (() => null);
    CLAN_ORDER = data.clanOrder.slice();
    CLANS = {};
    for (const k of CLAN_ORDER) {
      const c = data.clans[k];
      CLANS[k] = { key: k, name: c.name, color: colorFor(k), emblem: c.emblem, bonusText: c.bonus, bonus: parse(c.bonus) };
    }
    CARDS = data.cards.map((c) => ({
      id: c.id, name: c.name, clan: c.clan, rarity: c.rarity, stars: c.stars,
      power: c.power, damage: c.damage, art: c.art,
      abilityText: c.ability, ability: c.ability ? parse(c.ability) : null,
      abilityLevel: minLevel({ stars: c.stars }), // ability active at any playable level
    }));
    CARD_BY_ID = Object.fromEntries(CARDS.map((c) => [c.id, c]));

    const api = { CLANS, CLAN_ORDER, CARDS, CARD_BY_ID, cardStatsAtLevel, minLevel, xpForLevel, xpToMax, meta: data._meta };
    Object.assign(root, api);
    root.CardData = api;
    return api;
  }

  const ready = (async function () {
    const res = await fetch("data/cards-data.json", { cache: "no-cache" });
    if (!res.ok) throw new Error("Failed to load cards-data.json: " + res.status);
    return build(await res.json());
  })();
  root.URBC_DATA_READY = ready;

  // Node usage (build script / tests)
  if (typeof module !== "undefined" && module.exports) {
    module.exports = { build, cardStatsAtLevel, minLevel, xpForLevel, xpToMax, colorFor };
  }
})(typeof window !== "undefined" ? window : globalThis);
